{"content": "     1|/* ===== hostazar.com – Megapage JavaScript ===== */
     2|(function () {
     3|  'use strict';
     4|
     5|  const CAT_COLORS = {
     6|    gaming: { bg: 'rgba(76,175,80,0.2)', color: '#66bb6a' },
     7|    webhosting: { bg: 'rgba(33,150,243,0.2)', color: '#64b5f6' },
     8|    devops: { bg: 'rgba(255,152,0,0.2)', color: '#ffb74d' }
     9|  };
    10|  const CAT_LABELS = { gaming: 'Gaming', webhosting: 'Webhosting', devops: 'DevOps' };
    11|  const CAT_EMOJI = { gaming: '🎮', webhosting: '🌐', devops: '⚙️' };
    12|  const PAGE_SIZE = 12;
    13|
    14|  let app = {
    15|    catalog: [],
    16|    filtered: [],
    17|    currentPage: 1,
    18|    searchTerm: '',
    19|    activeCategory: 'all',
    20|    gridEl: null,
    21|    searchEl: null,
    22|    filterEl: null,
    23|    paginationEl: null,
    24|    articleCountEl: null
    25|  };
    26|
    27|  /* ---- helpers ---- */
    28|  function escapeHtml(s) {
    29|    const d = document.createElement('div');
    30|    d.textContent = s;
    31|    return d.innerHTML;
    32|  }
    33|
    34|  function buildCard(a) {
    35|    const catData = CAT_COLORS[a.category] || CAT_COLORS.gaming;
    36|    const catLabel = CAT_LABELS[a.category] || a.category;
    37|    const catEmoji = CAT_EMOJI[a.category] || '📄';
    38|    const imgSrc = `/images/${a.image}`;
    39|    return `
    40|<article class="blog-card" data-slug="${escapeHtml(a.slug)}" data-category="${escapeHtml(a.category)}" data-tags="${escapeHtml(a.tags ? a.tags.join(',') : '')}">
    41|  <a href="/artikel/${escapeHtml(a.slug)}.html" class="card-img-link">
    42|    <div class="card-img">
    43|      <img src="${imgSrc}" alt="${escapeHtml(a.title)}" loading="lazy" onerror="this.parentElement.innerHTML='<span class=\\'placeholder-icon\\'>${catEmoji}</span>'">
    44|    </div>
    45|  </a>
    46|  <div class="card-body">
    47|    <div class="card-meta">
    48|      <span class="card-tag ${escapeHtml(a.category)}" style="background:${catData.bg};color:${catData.color}">${catLabel}</span>
    49|      <span>${a.date || '2026'}</span>
    50|      ${a.readingTime ? `<span>· ${a.readingTime} Min</span>` : ''}
    51|    </div>
    52|    <h3><a href="/artikel/${escapeHtml(a.slug)}.html">${escapeHtml(a.title)}</a></h3>
    53|    <p class="card-excerpt">${escapeHtml(a.excerpt ? a.excerpt.substring(0, 150) + (a.excerpt.length > 150 ? '…' : '') : '')}</p>
    54|    <div class="card-footer">
    55|      <span class="read-more"><a href="/artikel/${escapeHtml(a.slug)}.html">Weiterlesen →</a></span>
    56|    </div>
    57|  </div>
    58|</article>`;
    59|  }
    60|
    61|  function renderCards() {
    62|    if (!app.gridEl) return;
    63|    const start = (app.currentPage - 1) * PAGE_SIZE;
    64|    const page = app.filtered.slice(start, start + PAGE_SIZE);
    65|    app.gridEl.innerHTML = page.length ? page.map(buildCard).join('') :
    66|      '<div class="no-results"><p>😕 Keine Artikel gefunden. <a href="#" class="search-reset-link">Filter zurücksetzen</a></p></div>';
    67|    renderPagination();
    68|
    69|    // Bind reset link
    70|    const resetLink = app.gridEl.querySelector('.search-reset-link');
    71|    if (resetLink) resetLink.addEventListener('click', function (e) { e.preventDefault(); app.resetFilters(); });
    72|  }
    73|
    74|  function renderPagination() {
    75|    const el = app.paginationEl;
    76|    if (!el) return;
    77|    const total = Math.ceil(app.filtered.length / PAGE_SIZE);
    78|    if (total <= 1) { el.innerHTML = ''; return; }
    79|    let html = '<div class="pagination">';
    80|    if (app.currentPage > 1) {
    81|      html += `<a href="#" data-page="${app.currentPage - 1}" class="page-btn prev">‹ Zurück</a>`;
    82|    }
    83|    for (let i = 1; i <= total; i++) {
    84|      if (i === app.currentPage) {
    85|        html += `<span class="page-btn active">${i}</span>`;
    86|      } else if (i === 1 || i === total || Math.abs(i - app.currentPage) <= 2) {
    87|        html += `<a href="#" data-page="${i}" class="page-btn">${i}</a>`;
    88|      } else if (Math.abs(i - app.currentPage) === 3) {
    89|        html += `<span class="page-dots">…</span>`;
    90|      }
    91|    }
    92|    if (app.currentPage < total) {
    93|      html += `<a href="#" data-page="${app.currentPage + 1}" class="page-btn next">Weiter ›</a>`;
    94|    }
    95|    html += '</div>';
    96|    el.innerHTML = html;
    97|
    98|    el.querySelectorAll('.page-btn[data-page]').forEach(function (btn) {
    99|      btn.addEventListener('click', function (e) {
   100|        e.preventDefault();
   101|        app.goToPage(parseInt(this.dataset.page));
   102|      });
   103|    });
   104|
   105|    updateArticleCount();
   106|  }
   107|
   108|  function updateArticleCount() {
   109|    if (!app.articleCountEl) return;
   110|    const total = app.filtered.length;
   111|    const showing = Math.min(PAGE_SIZE, total);
   112|    const start = (app.currentPage - 1) * PAGE_SIZE + 1;
   113|    app.articleCountEl.innerHTML = `<span class="result-count">${total} Artikel${app.searchTerm || app.activeCategory !== 'all' || app.activeTag ? ` gefunden (zeige ${start}–${Math.min(start + PAGE_SIZE - 1, total)})` : ''}</span>`;
   114|  }
   115|
   116|  /* ---- search ---- */
   117|  function doSearch() {
   118|    const q = app.searchEl ? app.searchEl.value.trim().toLowerCase() : '';
   119|    app.searchTerm = q;
   120|    applyFilters();
   121|  }
   122|
   123|  function applyFilters() {
   124|    let list = app.catalog;
   125|
   126|    // category filter
   127|    if (app.activeCategory !== 'all') {
   128|      list = list.filter(function (a) { return a.category === app.activeCategory; });
   129|    }
   130|
   131|    // tag filter
   132|    if (app.activeTag) {
   133|      list = list.filter(function (a) { return a.tags && a.tags.some(function (t) { return t.toLowerCase() === app.activeTag.toLowerCase(); }); });
   134|    }
   135|
   136|    // search
   137|    if (app.searchTerm) {
   138|      const q = app.searchTerm;
   139|      list = list.filter(function (a) {
   140|        return (a.title && a.title.toLowerCase().indexOf(q) !== -1) ||
   141|          (a.excerpt && a.excerpt.toLowerCase().indexOf(q) !== -1) ||
   142|          (a.tags && a.tags.some(function (t) { return t.toLowerCase().indexOf(q) !== -1; }));
   143|      });
   144|    }
   145|
